do $$
begin
  if not exists (
    select 1 from public.perfis
    where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
      and lower(coalesce(nome, '')) like '%filipe%'
  ) then
    raise exception 'Perfil do Filipe n?o encontrado; importa??o cancelada.';
  end if;

  if not exists (
    select 1
    from public.cartoes_credito
    where id = 'a66a994f-2faf-49c8-a1ef-d8bf11e35902'::uuid
      and usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
      and conta_id = '45716256-15d3-4496-88ba-8af9fb04753d'::uuid
      and final_cartao = '6803'
  ) then
    raise exception 'Cart?o Ita? Uniclass final 6803 n?o encontrado; importa??o cancelada.';
  end if;
end;
$$;

