  total_abril numeric(14, 2);
  total_maio numeric(14, 2);
  total_junho numeric(14, 2);
begin
  select count(*),
    coalesce(sum(case when mes_competencia = '2026-03-01'::date then case when natureza = 'despesa' then valor else -valor end else 0 end), 0),
    coalesce(sum(case when mes_competencia = '2026-04-01'::date then case when natureza = 'despesa' then valor else -valor end else 0 end), 0),
    coalesce(sum(case when mes_competencia = '2026-05-01'::date then case when natureza = 'despesa' then valor else -valor end else 0 end), 0),
    coalesce(sum(case when mes_competencia = '2026-06-01'::date then case when natureza = 'despesa' then valor else -valor end else 0 end), 0)
  into quantidade, total_marco, total_abril, total_maio, total_junho
  from public.movimentacoes
  where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
    and conta_id = '45716256-15d3-4496-88ba-8af9fb04753d'::uuid
    and metadados ->> 'importacao_lote' = 'itau-filipe-2026-03-a-06';

