      and grupo_parcelas_id in ('05775fbd-7685-4b5f-9ff5-37f51266b6ba'::uuid, '0a9e5332-2450-4737-b66a-73f871aaedaa'::uuid, '196b3738-ad09-5abe-818a-d27b4306594b'::uuid, '276364ec-0bc7-5563-926b-76c59088b0c8'::uuid, '456c3657-61a9-41aa-ab40-6947d4190e35'::uuid, '48c04c02-9dfc-4020-9f38-a67eda1c33b0'::uuid, '4b310cd5-33ea-4815-9b42-b5100b56a0e6'::uuid, '4c053260-ff30-4654-aada-18b5104883b6'::uuid, '556f3dd6-ef46-5e5e-a87c-b3d60073ef1a'::uuid, '6dd9a53b-3cd7-4de5-b5ba-d22bb7cf8e92'::uuid, '70e1c8d7-58b9-587d-8d2a-7e0f616c43b4'::uuid, 'a1ef1fb0-1103-4f65-bb51-e92f5726351d'::uuid, 'b25fa86a-ad4f-4141-8fac-ae3b85740bd0'::uuid, 'c25406bd-3569-4b8d-a58a-56e0181828e2'::uuid, 'ddd53f53-18f3-55db-b06a-1a308fe8236a'::uuid, 'ea12c26a-da15-5873-abf1-8537b52a9416'::uuid)
